def check_palindrome(s):
    if s == s[::-1]:
        return True
    return False


def min_changes(s):
    s_list = list(s)
    s_list.reverse()
    for i in range(len(s)):
        if s_list[i] == s[i]:
            s_list[i] = s[i]
        else:
            s_list[i] = s[i]
    s = ''.join(s_list)
    return s


if __name__ == "__main__":
    s = input()
    if check_palindrome(s):
        print(s)
    else:
        print(min_changes(s))
